# Category: serverless_security

import os
import json
import logging
from datetime import datetime, timezone

import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
import requests

app = func.FunctionApp()

credential = DefaultAzureCredential()

STORAGE_ACCOUNT_URL = os.environ["STORAGE_ACCOUNT_URL"]
COSMOS_ENDPOINT = os.environ["COSMOS_ENDPOINT"]
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "mvpdb")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "results")
COSMOS_PARTITION_KEY = os.environ.get("COSMOS_PARTITION_KEY", "/id")
EVENT_GRID_TOPIC_ENDPOINT = os.environ["EVENT_GRID_TOPIC_ENDPOINT"]
EVENT_GRID_TOPIC_KEY = os.environ.get("EVENT_GRID_TOPIC_KEY", "")

blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(COSMOS_ENDPOINT, credential=credential)

try:
    cosmos_db = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    cosmos_container = cosmos_db.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key=PartitionKey(path=COSMOS_PARTITION_KEY),
        offer_throughput=400,
    )
except Exception:
    cosmos_db = cosmos_client.get_database_client(COSMOS_DATABASE_NAME)
    cosmos_container = cosmos_db.get_container_client(COSMOS_CONTAINER_NAME)


def _send_event(subject: str, event_type: str, data: dict):
    payload = [
        {
            "id": f"{datetime.now(timezone.utc).timestamp()}",
            "eventType": event_type,
            "subject": subject,
            "eventTime": datetime.now(timezone.utc).isoformat(),
            "data": data,
            "dataVersion": "1.0",
            "metadataVersion": "1",
        }
    ]
    headers = {
        "Content-Type": "application/json",
        "aeg-sas-key": EVENT_GRID_TOPIC_KEY,
    }
    requests.post(EVENT_GRID_TOPIC_ENDPOINT, headers=headers, data=json.dumps(payload), timeout=10)


def _process_blob(container_name: str, blob_name: str):
    container_client = blob_service_client.get_container_client(container_name)
    blob_client = container_client.get_blob_client(blob_name)
    blob_data = blob_client.download_blob().readall()
    content_text = blob_data.decode("utf-8", errors="replace")

    result = {
        "id": f"{container_name}:{blob_name}",
        "container": container_name,
        "blob": blob_name,
        "size": len(blob_data),
        "processedAt": datetime.now(timezone.utc).isoformat(),
        "preview": content_text[:1000],
    }

    cosmos_container.upsert_item(result)

    _send_event(
        subject=f"/blobs/{container_name}/{blob_name}",
        event_type="BlobProcessed",
        data={
            "container": container_name,
            "blob": blob_name,
            "recordId": result["id"],
            "size": result["size"],
            "processedAt": result["processedAt"],
        },
    )


@app.function_name(name="ProcessBlobTrigger")
@app.blob_trigger(
    arg_name="blob",
    path="%BLOB_CONTAINER_NAME%/{name}",
    connection="AzureWebJobsStorage",
)
def process_blob_trigger(blob: func.InputStream):
    try:
        container_name = os.environ["BLOB_CONTAINER_NAME"]
        blob_name = blob.name.split("/", 1)[-1]
        _process_blob(container_name, blob_name)
        logging.info("Processed blob %s/%s", container_name, blob_name)
    except Exception as ex:
        logging.exception("Failed processing blob: %s", ex)
        raise


@app.function_name(name="ProcessBlobHttp")
@app.route(route="process-blob", auth_level=func.AuthLevel.FUNCTION, methods=["POST"])
def process_blob_http(req: func.HttpRequest) -> func.HttpResponse:
    try:
        body = req.get_json()
        container_name = body["container"]
        blob_name = body["blob"]
        _process_blob(container_name, blob_name)
        return func.HttpResponse(
            json.dumps({"status": "ok", "container": container_name, "blob": blob_name}),
            mimetype="application/json",
            status_code=200,
        )
    except Exception as ex:
        logging.exception("Failed processing request: %s", ex)
        return func.HttpResponse(
            json.dumps({"status": "error", "message": str(ex)}),
            mimetype="application/json",
            status_code=500,
        )